import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Ensure that the input length does not exceed the buffer size
        int bufferSize = 10;
        byte[] buffer = new byte[bufferSize];

        // Copy a safe amount of bytes from user input into the buffer
        int bytesToCopy = Math.min(input.length(), bufferSize);
        System.arraycopy(input.getBytes(), 0, buffer, 0, bytesToCopy);

        // Print out the content of the buffer
        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
